mapper.select:
SELECT id, name, created_at, deleted_at
FROM equipments
WHERE id = #{id}

SELECT id, name, created_at, deleted_at
FROM equipments
WHERE name = #{name}

mapper.update:
UPDATE equipments
SET name = #{name}, deleted_at = #{deletedAt}
WHERE id = #{id}

UPDATE equipments
SET deleted_at = NOW()
WHERE id = #{id}

UPDATE venue_equipment_map
SET quantity = #{quantity}
WHERE venue_id = #{venueId}
AND equipment_id = #{equipmentId}

mapper.delete:
DELETE FROM venue_equipment_map
WHERE venue_id = #{venueId}
AND equipment_id = #{equipmentId}
